#!/usr/bin/env bash
# t2i-decay-risk-low-last-updated-.sh — 单张精控出图（文生图 T2I 全链）(Decay risk: low) last_updated: 2026-06-22 SOP walkthrough for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
WORKFLOW="单张精控出图（文生图 T2I 全链）(Decay risk: low) last_updated: 2026-06-22"

usage() {
  cat <<EOF
t2i-decay-risk-low-last-updated-.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./t2i-decay-risk-low-last-updated-.sh             # interactive
  ./t2i-decay-risk-low-last-updated-.sh --dry-run
  ./t2i-decay-risk-low-last-updated-.sh --json
  ./t2i-decay-risk-low-last-updated-.sh --explain
  ./t2i-decay-risk-low-last-updated-.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "单张精控出图（文生图 T2I 全链）(Decay risk: low) last_updated: 2026-06-22" 工作流。

一句话: 从一个画面概念，经选底模→写 prompt 调参数→出图筛方向→迭代→放大精修，落地成一张可交付且可复现的成图。从「脑子里的画面」到「磁盘上带参数的成图」。

入门 SOP 共 7 步, 失败模式自检 3 项。

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**选底模**：按需求选 checkpoint（SDXL 资产最厚 / Flux 画质与文字强 / SD1.5 低显存兜底）。Load Checkpoint 节点加载。(evidence: [T03-S001])"
  "**写 prompt**：正面 prompt（主体+风格+细节+质量词）、负面 prompt 分别进两个 CLIP Text Encode 节点。(evidence: [T03-S001])"
  "**设画布与参数**：Empty Latent 设分辨率（SDXL 用 1024 系），KSampler 设 steps（约 25 起步）、CFG（7 左右）、采样器（Euler/DPM++）、scheduler、seed、denoise=1.0。(evidence: [T03-S001])"
  "**首轮出图筛方向**：先小批量/随机 seed 跑几张，挑构图与方向对的那张（「抽卡」阶段）。"
  "**迭代收敛**：锁定满意 seed，微调 prompt 措辞/权重、CFG、采样器；逐层把随机性收掉。"
  "**放大精修**：VAE Decode 后接放大链（ESRGAN 纯放大 / Ultimate SD Upscale 分块重绘加细节 / SUPIR 重绘补细节）到交付分辨率。(evidence: [T03-S021])"
  "**留参数交付**：Save Image（PNG 内嵌工作流元数据），记录全套参数。"
)
declare -a FAILURE_MODES=(
  "**在错误构图上精修浪费算力**：没先小图筛方向就 4K 放大 —— 先在 512/768 出 4-8 张筛方向，方向对再放大，省 80% 算力。"
  "**CFG/steps 盲目拉满**：CFG 拉到 20+ 出油腻过曝、steps 拉到 80 纯浪费时间零收益 —— CFG 守 5-8、steps 守 20-30，画质问题先查 prompt 与放大链而非拉参数。"
  "**没记参数无法复现**：交付后客户要改一处，原图 seed/参数没存 —— 用 ComfyUI PNG 内嵌元数据或建立参数台账，每张交付图存全参数。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "t2i-decay-risk-low-last-updated--walkthrough"
fi
